// When triggered by webhook, use that risk data directly
// When triggered by schedule, the risks come from the HTTP call above
let risks = [];
let source = 'schedule';

if ($input.first().json.body && $input.first().json.body.risks) {
  // Webhook path - bridge service already ran AI analysis
  risks = $input.first().json.body.risks;
  source = 'webhook';
} else {
  // Schedule path - need to analyze from contact data
  // This is a fallback; primary analysis runs in the bridge service
  risks = [];
  source = 'schedule-fallback';
}

if (risks.length === 0) {
  return [{ json: { noRisks: true, source } }];
}

// Split risks into items for parallel processing
return risks.map(risk => ({ json: { ...risk, source } }));

// Group all risk items into a single Slack message
const items = $input.all();

const highRisk = items.filter(i => i.json.riskLevel === 'high');
const mediumRisk = items.filter(i => i.json.riskLevel === 'medium');

const formatRisk = (item) => {
  const reasons = (item.json.riskReasons || []).join(', ');
  const actions = (item.json.recommendedActions || []).slice(0, 2).join(' | ');
  return `• *Contact ${item.json.contactId}* — ${reasons}\n  _Actions: ${actions}_`;
};

let messageText = `📊 *Daily Deal Health Report* — ${new Date().toLocaleDateString()}\n`;
messageText += `*${items.length} deals need attention*\n\n`;

if (highRisk.length > 0) {
  messageText += `🔴 *HIGH RISK (${highRisk.length}):*\n${highRisk.map(formatRisk).join('\n')}\n\n`;
}
if (mediumRisk.length > 0) {
  messageText += `🟡 *MEDIUM RISK (${mediumRisk.length}):*\n${mediumRisk.map(formatRisk).join('\n')}\n`;
}

return [{ json: { text: messageText, riskCount: items.length, highCount: highRisk.length } }];

